class Solution:
    def countBinarySubstrings(self, s: str) -> int:
        groups=[]; i=0
        while i<len(s):
            j=i
            while j<len(s) and s[j]==s[i]: j+=1
            groups.append(j-i); i=j
        ans=0
        for i in range(1,len(groups)): ans+=min(groups[i-1],groups[i])
        return ans

