class Solution {
public:
    int countBinarySubstrings(string s) {
        vector<int> g; int i=0;
        while(i<(int)s.size()){
            int j=i; while(j<(int)s.size()&&s[j]==s[i]) j++;
            g.push_back(j-i); i=j;
        }
        int ans=0; for(int k=1;k<(int)g.size();k++) ans+=min(g[k-1],g[k]);
        return ans;
    }
};
